object AWSIntegrationExample {
  def main(args: Array[String]): Unit = {
    val credentials = StaticCredentials("your-access-key", "your-secret-key")
    val region = Region.US_EAST_1
    val manager = new AWSServiceManager(credentials, region)

    val s3Service = manager.getS3Service
    s3Service.createBucket("my-test-bucket") match {
      case Success(_) => println("Bucket created successfully")
      case Failure(e) => println(s"Failed to create bucket: ${e.getMessage}")
    }

    s3Service.uploadContent("my-test-bucket", "test.txt", "Hello AWS!") match {
      case Success(_) => println("File uploaded successfully")
      case Failure(e) => println(s"Failed to upload file: ${e.getMessage}")
    }

    s3Service.listObjects("my-test-bucket") match {
      case Success(objects) => println(s"Objects in bucket: ${objects.mkString(", ")}")
      case Failure(e) => println(s"Failed to list objects: ${e.getMessage}")
    }

    val dynamoService = manager.getDynamoDBService
    dynamoService.createTable("my-table", "id") match {
      case Success(_) => println("Table created successfully")
      case Failure(e) => println(s"Failed to create table: ${e.getMessage}")
    }

    val item = Map(
      "id" -> AttributeValue.builder().s("123").build(),
      "name" -> AttributeValue.builder().s("John Doe").build()
    )
    dynamoService.putItem("my-table", item) match {
      case Success(_) => println("Item inserted successfully")
      case Failure(e) => println(s"Failed to insert item: ${e.getMessage}")
    }

    val sqsService = manager.getSQSService
    sqsService.createQueue("my-queue") match {
      case Success(queueUrl) => 
        println(s"Queue created: $queueUrl")
        sqsService.sendMessage(queueUrl, "Hello SQS!")
      case Failure(e) => println(s"Failed to create queue: ${e.getMessage}")
    }

    s3Service.close()
    dynamoService.close()
    sqsService.close()
  }
}